```js-com
// 1단계: PPT 실행 + 기본 설정
var presentation = ppt.Presentations.Add();
ppt.Activate();

// 슬라이드 크기 설정 (와이드스크린 16:9)
presentation.PageSetup.SlideWidth = 720;   // 25.4cm
presentation.PageSetup.SlideHeight = 405;  // 14.29cm

// 기본 슬라이드 삭제 (빈 슬라이드로 시작)
var slides = presentation.Slides;

console.log("슬라이드 수: " + slides.Count);
console.log("슬라이드 크기: " + presentation.PageSetup.SlideWidth + " x " + presentation.PageSetup.SlideHeight);

result = "PPT 생성 완료";
```

