subTf.TextRange.Text = "엔터프라이즈 AI RAG 에이전트 | 일본 글로벌 시장 진출";
subTf.TextRange.Font.Size = 18;
subTf.TextRange.Font.Color.RGB = 0xCCDDEE;
subTf.TextRange.Font.Name = "Pretendard";

// 날짜
