var dateTf = dateBox.TextFrame;
dateTf.TextRange.Text = "2026년 2월 19일";
dateTf.TextRange.Font.Size = 13;
dateTf.TextRange.Font.Color.RGB = 0x8899AA;
dateTf.TextRange.Font.Name = "Pretendard";

